import React from 'react';
import { Link } from 'react-router-dom';
import TopicsManager from './TopicsManager';
import './Sidebar.css';

function Sidebar({ blogs, loading, topics, onTopicsChange }) {
  return (
    <aside className="sidebar">
      <div className="sidebar-top">
        <div className="sidebar-title">Blog posts</div>
        {loading ? (
          <div className="sidebar-loading">Loading posts...</div>
        ) : (
          <nav className="sidebar-blog-list">
            {blogs.length === 0 ? (
              <div className="sidebar-empty">No posts yet</div>
            ) : (
              blogs.map(blog => (
                <Link
                  key={blog.id}
                  to={`/blog/${blog.id}`}
                  className="sidebar-blog-link"
                >
                  {blog.title}
                </Link>
              ))
            )}
          </nav>
        )}
      </div>

      <div className="sidebar-bottom">
        <div className="sidebar-topic-label">Topics</div>
        <div className="sidebar-topics">
          {topics.length === 0 ? (
            <div className="sidebar-empty">No topics yet</div>
          ) : (
            topics.map(topic => (
              <div key={topic.id || topic.name || topic} className="sidebar-topic">
                {topic.name || topic}
              </div>
            ))
          )}
        </div>
        <TopicsManager topics={topics} onTopicsChange={onTopicsChange} />
      </div>
    </aside>
  );
}

export default Sidebar;
